:root {
  --bg: #0A0A0B;
  --elev-1: #111113;
  --elev-2: #16161A;
  --border: rgba(255,255,255,0.08);
  --border-soft: rgba(255,255,255,0.06);
  --border-strong: rgba(255,255,255,0.14);
  --text: #ECECEE;
  --text-muted: #8A8A93;
