  --magenta-soft: rgba(229, 38, 124, 0.14);
  --magenta-bg: rgba(229, 38, 124, 0.08);
  --green: #2D6A4F;
  --amber: #8B6B1F;
  --red: #7A2E2E;
}

* { box-sizing: border-box; }
html, body {
  margin: 0; padding: 0;
  background: var(--bg);
  color: var(--text);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
